SELECT model_name
FROM equipment_models
WHERE model_id = 1;

SELECT AVG(power) AS average_power
FROM gross_powers
WHERE gross_power_type = 'Maximum';

SELECT MAX(power) AS maximum_power
FROM gross_powers
WHERE model_id = 1;

SELECT MAX(torque) AS max_gross_torque
FROM gross_torques
WHERE gross_torque_type = 'Maximum';

SELECT model_id, power, unit, gross_power_type
FROM gross_powers
WHERE power = (SELECT MAX(power) FROM gross_powers);

SELECT model_name AS "Equipment Name"
FROM equipment_models
ORDER BY model_name;

SELECT size
FROM engine_sizes
WHERE engine_type = 'Diesel' AND unit = 'L (549 cu. in.)';

SELECT model_id, MAX(weight) AS max_operating_weight
FROM operating_weights
GROUP BY model_id;

SELECT model_name, manufacturer_id
FROM equipment_models
ORDER BY model_name;
